### UNC decades table


::: {.cell}

```{.r .cell-code}
heels_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/ncaa/500/153.png'
       style='height: 55px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Carolina hoops over the past five decades</span>
       <span style='font-size: 12.5px; font-weight: normal; display: block; text-align: center;'>Performance across the ACC, NCAA Tournament, and overall win percentage.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png' 
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)


unc_decade_tbl <- unc_hist |> 
  dplyr::mutate(record = paste0(Total_Wins, "-", Total_Losses)) |> 
  dplyr::relocate(Win_Percentage, .after = Titles) |>
  dplyr::relocate(NBA, .after = Decade) |>
  dplyr::mutate(
    Titles = dplyr::case_when(
    Titles %% 1 == 0 ~ strrep("trophy,", Titles),
    Titles %% 1 != 0 ~ paste0(strrep("trophy,", floor(Titles)), "trophy"))
  ) |> 
  gt::gt() |> 
  gtUtils::gt_theme_gtutils() |> 
  gt::fmt_icon(
    columns = c(Titles),
    rows = c(1, 2, 3, 4),
    fill_color = "orange"
  ) |> 
  gt::cols_hide(columns = c(Total_Wins, Total_Losses, NBA)) |> 
  gt::fmt_number(Win_Percentage, decimals = 3) |> 
  gtExtras::gt_merge_stack(
    col1 = Win_Percentage,
    col2 = record,
    palette = c("black", "#333333")
  ) |> 
  gtUtils::gt_column_subheaders(
    Win_Percentage = list(heading = "Win %", subtitle = "W-L"),
    #NBA = list(heading = "1st Round", subtitle = "# of Picks"),
    ACCT = list(heading = "Tournament", subtitle = "Titles"),
    RS = list(heading = "Regular", subtitle = "Season"),
    F4 = list(heading = "Final Fours", subtitle = "# of times"),
    Titles = list(heading = "Titles", subtitle = "# of titles"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |> 
  gt::tab_spanner(
    columns = c(ACCT, RS),
    label = "ACC Championships"
  ) |> 
  gt::tab_spanner(
    columns = c(F4, Titles),
    label = "NCAA Tournament"
  ) |> 
  #gt::tab_spanner(
  #  columns = NBA,
  #  label = "NBA Draft"
  #) |> 
  gt::cols_label(
    Decade = ""
  ) |> 
  gt::cols_nanoplot(
    columns = Yearly_Win_Pcts,
    reference_line = .70,
    autohide = TRUE,
    plot_type = "line",
    new_col_label = "Over time",
    options = gt::nanoplot_options(
      data_area_fill_color = "#56a0d3",
      reference_line_color = "#333333",
      show_data_area = TRUE,
      show_data_points = FALSE
    )
  ) |> 
  gt::tab_header(title = gt::html(heels_header)) |>
  gt::tab_source_note(source_note = gt::html("<hr>Over time column shows win percentage by season throughout the decade (dashed line indicates a .700 win percentage).<br>Decades include the season's final year (i.e. 2019-20 is part of the 2020s)<hr><br><b>Table by Chris at Bless your Chart | data via sports-reference.com | April 4, 2025</b>")) |> 
  gt::data_color(
    columns = c(NBA, ACCT, RS, F4, Win_Percentage),
    direction = c("column"),
    method = c("numeric"),
    palette = c("#d7191c", "#fdae61", 
                "#ffffbf", "#a6d96a", 
                "#1a9641"),
    alpha = 0.6
  ) |>
  gt::tab_style(
    locations = gt::cells_column_labels(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = "650",
      size = gt::px(14)
    )
  ) |> 
  gt::tab_style(
    locations = gt::cells_body(columns = Decade),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = "bold"
    )
  ) |> 
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(14)
    )
  ) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 2,
                          include_labels = FALSE) |> 
  gtUtils::gt_border_bars_bottom(c("#56a0d3", "#89BDE0", "#BBD9ED")) |> 
  gt::tab_options(table.width = gt::px(700))


gtUtils::gt_save_crop(
  unc_decade_tbl,
  file = "unc_decade_tbl.png",
  whitespace = 60,
  bg = "#FFFDF5"
)

unc_decade_tbl
