### Continuity plot


::: {.cell}

```{.r .cell-code}
cont_plot <- cont_data |> 
   dplyr::filter(Metric == "Continuity (minutes)") |> 
  ggplot2::ggplot(ggplot2::aes(x = season, y = Value, color = Metric)) +
  ggplot2::geom_smooth(method = "loess", se = FALSE, span = 0.35) +
  ggplot2::geom_vline(xintercept = 2021.5, linetype = "dotted", color = "#333333", linewidth = 0.5) +
  ggplot2::scale_color_manual(values = 
                                c("Continuity (minutes)" = "#998ec3")) +
  hrbrthemes::theme_ipsum_rc() +
  ggplot2::labs(
    title = "The decline of continuity in college basketball",
    subtitle = "Shows the median Division I continuity of minutes since the 2010 season.",
    x = "Season",
    y = "",
    caption ="Data via kenpom.com | Viz by Chris at Bless your Chart"
  ) +
  ggplot2::scale_y_continuous(limits = c(30, 55), 
                              breaks = seq(30, 55, 5)) +
  ggplot2::theme(legend.position = "none") +
  ggplot2::annotate(
    geom = "label",
    x = 2024,
    y = 52.5,
    color = "#333333",
    fill = "floralwhite",
    label = "Transfer without  \npenalty",
    size = 3.5,
    fontface = 'bold',
    family = 'Roboto condensed'
  ) +
  ggplot2::annotate(
    geom = "curve",
    color = "#333333",
    x = 2022.9,
    y = 52.2,
    xend = 2021.6,
    yend = 48.5,
    curvature = .5,
    linewidth = 0.6,
    arrow = ggplot2::arrow(length = ggplot2::unit(2, "mm"))
  ) +
  ggplot2::annotate(
    geom = "text",
    x = 2025,
    y = 33.4,
    color = "#333333",
    label = "33.7",
    size = 4,
    fontface = 'bold',
    family = 'Roboto condensed'
  ) +
  ggplot2::annotate(
    geom = "text",
    x = 2010,
    y = 53.9,
    color = "#333333",
    label = "53.1",
    size = 4,
    fontface = 'bold',
    family = 'Roboto condensed'
  )

ggplot2::ggsave(
  "cont_plot.png",
  cont_plot,
  w = 7.5,
  h = 6.5,
  dpi = 600,
  bg = "white",
  type = 'cairo'
)

