### Mid-range plot


::: {.cell}

```{.r .cell-code}
mr_plot <- shot_profile |> 
  dplyr::filter(season > 2014) |> 
  tidyr::pivot_longer(cols = c(mid_two_rate, three_rate), 
                      names_to = "shot_type", 
                      values_to = "rate") |> 
  ggplot2::ggplot(ggplot2::aes(x = season, y = rate, color = shot_type,
                               linetype = shot_type)) +
  ggplot2::geom_smooth(method = "loess", se = FALSE, linewidth = 1.5) +
  ggplot2::scale_color_manual(values = c("mid_two_rate" = "#7fbf7b", 
                                         "three_rate" = "#af8dc3")) +
  ggplot2::scale_linetype_manual(values = c("mid_two_rate" = "dashed", 
                                            "three_rate" = "solid")) +
  ggplot2::labs(title = "Shot Selection Trends Over Time",
                x = "",
                y = "",
                color = "Shot Type") +
  hrbrthemes::theme_ipsum_rc() +
  ggplot2::labs(
    title = "The change in shot profiles over the last decade of college hoops",
    subtitle = "A comparison of three-point attempt rate and mid-range two-point rate.",
    x = "",
    y = "",
    caption ="Data via bartorvik.com | Viz by Chris at Bless your Chart"
  ) +
  ggplot2::scale_x_continuous(limits = c(2015, 2025), 
                              breaks = seq(2015, 2025, 1)) +
  ggplot2::scale_y_continuous(
    limits = c(0.30, 0.50), 
    breaks = seq(0.30, 0.50, 0.05),
    labels = scales::percent_format(accuracy = 1)
  ) +
  ggplot2::theme(legend.position = "none") +
  ggplot2::annotate(
    geom = "label",
    x = 2016.5,
    y = .32,
    color = "#333333",
    fill = "#af8dc3",
    label = "Percentage of all shots  \nfrom 3PT land",
    size = 4,
    fontface = 'bold',
    family = 'Roboto condensed',
    alpha = 0.6
  ) +
  ggplot2::annotate(
    geom = "label",
    x = 2016.5,
    y = .48,
    color = "#333333",
    fill = "#7fbf7b",
    label = "Percentage of 2PT shots  \nfrom mid-range",
    size = 4,
    fontface = 'bold',
    family = 'Roboto condensed',
    alpha = 0.6
  ) +
  ggplot2::annotate(
    geom = "label",
    x = 2022.6,
    y = .48,
    color = "#333333",
    fill = "floralwhite",
    label = "2025 season  \n3PT attempt rate \nsurpasses the 2PT  \nmid-range rate",
    size = 4,
    fontface = 'bold',
    family = 'Roboto condensed'
  ) +
  ggplot2::annotate(
    geom = "curve",
    color = "#af8dc3",
    x = 2023.7,
    y = .48,
    xend = 2025,
    yend = .395,
    curvature = -.5,
    linewidth = 0.8,
    arrow = ggplot2::arrow(length = ggplot2::unit(2, "mm"))
  ) +
  ggplot2::geom_vline(xintercept = 2024.7, linetype = "dotted", color = "gray50", linewidth = 1)

